import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function discoverAgents(registryAddress, chainName) {
  const events = await client.BaseService.getLogEventsByAddress(
    chainName, registryAddress
  );
  const registrations = (events.data?.items ?? []).filter(
    e => e.decoded?.name === "AgentRegistered"
  );
  return registrations.map(e => ({
    agent: e.decoded?.params?.find(p => p.name === "agent")?.value,
    timestamp: e.block_signed_at,
  }));
}
